5. export async function updateSession(request: NextRequest) {
6.   const response = NextResponse.next({
7.     request: {
8.       headers: request.headers,
9.     },
10.   });
11. 
12.   const { supabaseUrl, supabaseAnonKey } = getSupabaseEnv();
13. 
14.   const supabase = createServerClient(supabaseUrl, supabaseAnonKey, {
15.     cookies: {
16.       getAll() {
17.         return request.cookies.getAll();
18.       },
