20.         cookiesToSet.forEach(({ name, value, options }) => {
21.           response.cookies.set(name, value, options);
22.         });
23. 
24.         Object.entries(headers).forEach(([key, value]) => {
25.           response.headers.set(key, value);
26.         });
27.       },
28.     },
29.   });
30. 
31.   await supabase.auth.getUser();
32. 
33.   return response;
34. }

