'use server';

import { createAdminClient } from '@/lib/supabase/admin';
import { createClient } from '@/lib/supabase/server';
import { normalizeUsername, validateUsername } from '@/lib/username';
import { redirect } from 'next/navigation';

export type AuthState = {
  error?: string;
  message?: string;
};

function readField(formData: FormData, key: string) {
  const value = formData.get(key);

  if (typeof value !== 'string') {
    return '';
  }

  return value.trim();
}

async function cleanupCreatedUser(
  supabase: Awaited<ReturnType<typeof createClient>>,
  adminClient: ReturnType<typeof createAdminClient>,
  userId: string,
) {
  const { error: deleteError } = await adminClient.auth.admin.deleteUser(userId);
  const { error: signOutError } = await supabase.auth.signOut();

  return {
    deleteError,
    signOutError,
  };
}

export async function loginAction(
  _: AuthState,
  formData: FormData,
): Promise<AuthState> {
  const email = readField(formData, 'email');
  const password = readField(formData, 'password');

  if (!email || !password) {
    return {
      error: 'Email and password are required.',
    };
  }

  const supabase = await createClient();
  const { error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });

  if (error) {
    return {
      error: error.message,
    };
  }

  redirect('/dashboard');
}

export async function signupAction(
  _: AuthState,
  formData: FormData,
): Promise<AuthState> {
  const username = normalizeUsername(readField(formData, 'username'));
  const email = readField(formData, 'email');
  const password = readField(formData, 'password');

  const usernameError = validateUsername(username);

  if (usernameError) {
    return {
      error: usernameError,
    };
  }

  if (!email || !password) {
    return {
      error: 'Email and password are required.',
    };
  }

  const supabase = await createClient();
  const { data, error } = await supabase.auth.signUp({
    email,
    password,
  });

  if (error) {
    return {
      error: error.message,
    };
  }

  const userId = data.user?.id;

  if (!userId) {
    return {
      error: 'Signup succeeded, but the auth user record was not returned.',
    };
  }

  const adminClient = createAdminClient();
  const { data: existingProfile, error: profileLookupError } = await adminClient
    .from('profiles')
    .select('id')
    .eq('handle', username)
    .maybeSingle();

  if (profileLookupError) {
    await supabase.auth.signOut();
    return {
      error: profileLookupError.message,
    };
  }

  if (existingProfile) {
    await cleanupCreatedUser(supabase, adminClient, userId);
    return {
      error: 'Username is already taken.',
    };
  }

  const { error: profileCreateError } = await adminClient.from('profiles').insert({
    id: userId,
    handle: username,
  });

  if (profileCreateError) {
    const { deleteError, signOutError } = await cleanupCreatedUser(
      supabase,
      adminClient,
      userId,
    );

    if (deleteError || signOutError) {
      const cleanupError = deleteError?.message ?? signOutError?.message;
      return {
        error: `${profileCreateError.message} Cleanup failed: ${cleanupError}`,
      };
    }

    return {
      error: profileCreateError.message,
    };
  }

  if (data.session) {
    redirect('/dashboard');
  }

  return {
    message: 'Check your email to finish creating your account.',
  };
}

export async function logoutAction(): Promise<never> {
  const supabase = await createClient();
  const { error } = await supabase.auth.signOut();

  if (error) {
    throw new Error(error.message);
  }

  redirect('/login');
}

