18.   switchText: string;
19.   switchHref: string;
20.   switchLabel: string;
21. };
22. 
23. const initialState: AuthState = {};
24. 
25. type UsernameStatus = 'idle' | 'checking' | 'available' | 'unavailable';
26. 
27. export function SignupForm({
28.   action,
29.   title,
30.   description,
31.   submitLabel,
32.   switchText,
33.   switchHref,
34.   switchLabel,
35. }: SignupFormProps) {
36.   const [state, formAction, pending] = useActionState(action, initialState);
37.   const [username, setUsername] = useState('');
38.   const [status, setStatus] = useState<UsernameStatus>('idle');
39.   const [statusMessage, setStatusMessage] = useState('');
40.   const [statusError, setStatusError] = useState('');
41. 
42.   const validationError = validateUsername(normalizeUsername(username));
43.   const submitDisabled =
44.     pending || status === 'checking' || status === 'unavailable' || Boolean(validationError);
45. 
46.   async function checkUsernameAvailability() {
47.     const normalized = normalizeUsername(username);
48. 
49.     setUsername(normalized);
50.     setStatusError('');
51.     setStatusMessage('');
52. 
53.     if (!normalized) {
54.       setStatus('idle');
55.       return;
56.     }
57. 
58.     if (validationError) {
59.       setStatus('unavailable');
60.       setStatusError(validationError);
61.       return;
62.     }
63. 
64.     setStatus('checking');
65. 
66.     const response = await fetch(
67.       `/api/username-availability?username=${encodeURIComponent(normalized)}`,
68.       {
69.         method: 'GET',
70.         cache: 'no-store',
71.       },
72.     );
73. 
74.     const data: { available: boolean; message?: string } = await response.json();
75. 
76.     if (!response.ok) {
77.       setStatus('unavailable');
78.       setStatusError(data.message ?? 'Unable to verify username availability.');
79.       return;
80.     }
81. 
82.     if (data.available) {
83.       setStatus('available');
84.       setStatusMessage(data.message ?? 'Username is available.');
85.       return;
86.     }
87. 
88.     setStatus('unavailable');
