104.           <div>
105.             <label
106.               htmlFor="username"
107.               className="mb-2 block text-sm font-medium text-black"
108.             >
109.               Username
110.             </label>
111.             <input
112.               id="username"
113.               name="username"
114.               value={username}
115.               onChange={(event) => {
116.                 setUsername(normalizeUsername(event.target.value));
117.                 setStatus('idle');
118.                 setStatusError('');
119.                 setStatusMessage('');
120.               }}
121.               onBlur={checkUsernameAvailability}
122.               autoComplete="off"
123.               required
124.               minLength={3}
125.               maxLength={15}
126.               className="h-11 w-full rounded-xl border border-black/10 px-4 text-sm text-black outline-none transition placeholder:text-black/30 focus:border-black/30"
127.               placeholder="your_handle"
128.             />
129.             {statusError ? (
130.               <p className="mt-2 text-sm text-red-600">{statusError}</p>
131.             ) : null}
132.             {statusMessage ? (
133.               <p className="mt-2 text-sm text-emerald-600">{statusMessage}</p>
134.             ) : null}
135.           </div>
136. 
137.           <div>
138.             <label
139.               htmlFor="email"
140.               className="mb-2 block text-sm font-medium text-black"
141.             >
142.               Email
143.             </label>
144.             <input
145.               id="email"
146.               name="email"
147.               type="email"
148.               autoComplete="email"
149.               required
150.               className="h-11 w-full rounded-xl border border-black/10 px-4 text-sm text-black outline-none transition placeholder:text-black/30 focus:border-black/30"
151.             />
152.           </div>
153. 
154.           <div>
155.             <label
156.               htmlFor="password"
157.               className="mb-2 block text-sm font-medium text-black"
158.             >
159.               Password
