2. import { createAdminClient } from '@/lib/supabase/admin';
3. import { normalizeUsername, validateUsername } from '@/lib/username';
4. 
5. export async function GET(request: Request) {
6.   const { searchParams } = new URL(request.url);
7.   const username = normalizeUsername(searchParams.get('username') ?? '');
8.   const validationError = validateUsername(username);
9. 
10.   if (validationError) {
11.     return NextResponse.json(
