1. 'use server';
2. 
3. import { createAdminClient } from '@/lib/supabase/admin';
4. import { createClient } from '@/lib/supabase/server';
5. import {
6.   isUsernameAvailable,
7.   normalizeUsername,
8.   validateUsername,
9. } from '@/lib/username';
10. import { redirect } from 'next/navigation';
11. 
12. export type AuthState = {
13.   error?: string;
14.   message?: string;
15. };
16. 
17. function readField(formData: FormData, key: string, trim = true) {
18.   const value = formData.get(key);
19. 
20.   if (typeof value !== 'string') {
21.     return '';
22.   }
23. 
24.   return trim ? value.trim() : value;
25. }
26. 
27. async function cleanupCreatedUser(
28.   supabase: Awaited<ReturnType<typeof createClient>>,
29.   adminClient: ReturnType<typeof createAdminClient>,
30.   userId: string,
31. ) {
32.   const { error: deleteError } = await adminClient.auth.admin.deleteUser(userId);
33.   const { error: signOutError } = await supabase.auth.signOut();
34. 
35.   return deleteError?.message ?? signOutError?.message ?? null;
36. }
37. 
38. export async function loginAction(
39.   _: AuthState,
40.   formData: FormData,
41. ): Promise<AuthState> {
42.   const email = readField(formData, 'email');
43.   const password = readField(formData, 'password');
44. 
45.   if (!email || !password) {
46.     return {
47.       error: 'Email and password are required.',
48.     };
49.   }
50. 
51.   const supabase = await createClient();
52.   const { error } = await supabase.auth.signInWithPassword({
53.     email,
54.     password,
55.   });
56. 
57.   if (error) {
58.     return {
59.       error: error.message,
60.     };
61.   }
62. 
63.   redirect('/dashboard');
64. }
65. 
66. export async function signupAction(
67.   _: AuthState,
68.   formData: FormData,
69. ): Promise<AuthState> {
70.   const username = normalizeUsername(readField(formData, 'username', false));
71.   const email = readField(formData, 'email');
72.   const password = readField(formData, 'password');
73. 
74.   const usernameError = validateUsername(username);
75. 
76.   if (usernameError) {
77.     return {
78.       error: usernameError,
79.     };
80.   }
81. 
82.   if (!email || !password) {
83.     return {
84.       error: 'Email and password are required.',
85.     };
86.   }
87. 
88.   const supabase = await createClient();
89.   const adminClient = createAdminClient();
90. 
91.   try {
92.     const availableBeforeSignup = await isUsernameAvailable(username);
93. 
94.     if (!availableBeforeSignup) {
95.       return {
96.         error: 'Username is already taken.',
97.       };
98.     }
99.   } catch (error) {
100.     const message = error instanceof Error ? error.message : 'Unknown error';
101. 
102.     return {
103.       error: message,
104.     };
105.   }
106. 
107.   const { data, error } = await supabase.auth.signUp({
108.     email,
109.     password,
110.   });
111. 
112.   if (error) {
113.     return {
114.       error: error.message,
115.     };
116.   }
117. 
118.   const userId = data.user?.id;
119. 
120.   if (!userId) {
121.     await supabase.auth.signOut();
122.     return {
123.       error: 'Signup succeeded, but the auth user record was not returned.',
124.     };
125.   }
126. 
127.   try {
128.     const availableAfterSignup = await isUsernameAvailable(username);
129. 
130.     if (!availableAfterSignup) {
131.       const cleanupError = await cleanupCreatedUser(supabase, adminClient, userId);
132.       return {
133.         error: cleanupError
134.           ? `Username is already taken. Cleanup failed: ${cleanupError}`
135.           : 'Username is already taken.',
136.       };
137.     }
