import 'server-only';

import { Resend } from 'resend';
import { EmailTemplate } from '@/components/email-template';
import { getAppUrl, getResendFromAddress } from '@/lib/mail';

const resendApiKey = process.env.RESEND_API_KEY;
const resend = resendApiKey ? new Resend(resendApiKey) : null;

type WelcomeEmailInput = {
  to: string;
  username: string;
};

export async function sendWelcomeEmail({ to, username }: WelcomeEmailInput) {
  if (!resend) {
    console.error('[welcome-email] Missing RESEND_API_KEY');
    return {
      ok: false,
      error: 'Missing RESEND_API_KEY',
    };
  }

  const loginUrl = `${getAppUrl()}/login`;
  const from = getResendFromAddress();

  console.info('[welcome-email] Sending welcome email', {
    to,
    from,
    loginUrl,
    hasApiKey: Boolean(resendApiKey),
  });

  try {
    const { data, error } = await resend.emails.send({
      from,
      to,
      subject: 'Welcome to Bookmark Manager',
      react: EmailTemplate({ username, loginUrl }),
    });

    if (error) {
      console.error('[welcome-email] Resend returned an error', {
        to,
        from,
        message: error.message,
      });
      return {
        ok: false,
        error: error.message,
      };
    }

    console.info('[welcome-email] Resend accepted email', {
      to,
      from,
      id: data?.id,
    });

    return { ok: true as const };
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    console.error('[welcome-email] Send threw', {
      to,
      from,
      message,
    });

    return {
      ok: false,
      error: message,
    };
  }
}

